import{_ as a,a as d,b as t,c as i,d as o,e as n,f as s,g as l}from"./chunks/无关系记录重新申请.D_1qirb1.js";import{_ as r,o as p,c,a2 as h}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Federated Distributed Index","description":"","frontmatter":{},"headers":[],"relativePath":"ps/Other/federated-distributed-index.md","filePath":"ps/Other/federated-distributed-index.md","lastUpdated":1781962217000}'),u={name:"ps/Other/federated-distributed-index.md"};function b(m,e,f,x,g,q){return p(),c("div",null,[...e[0]||(e[0]=[h('<h1 id="federated-distributed-index" tabindex="-1">Federated Distributed Index <a class="header-anchor" href="#federated-distributed-index" aria-label="Permalink to &quot;Federated Distributed Index&quot;">​</a></h1><p>Federated distributed index څو ImgBed sites ته اجازه ورکوي چې د files lists یو له بل سره share کړي.</p><p>په ساده ډول:</p><ul><li>له خپل site څخه ټاکلي folders نورو سره share کولای شئ.</li><li>بل node ته join کېدای شئ او د هغه node shared file list خپل admin panel ته sync کولای شئ.</li><li>Federated files عموما د browsing، searching او links پرانیستلو لپاره دي. دا ستاسو خپل storage ته بیا upload نه کېږي.</li></ul><h2 id="چېرته-یې-تنظیم-کړئ" tabindex="-1">چېرته یې تنظیم کړئ <a class="header-anchor" href="#چېرته-یې-تنظیم-کړئ" aria-label="Permalink to &quot;چېرته یې تنظیم کړئ&quot;">​</a></h2><p>دا پرانیزئ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Federated Distributed Index</span></span></code></pre></div><p><img src="'+a+`" alt="Local federation node" loading="lazy"></p><p>پاڼه درې tabs لري:</p><table tabindex="0"><thead><tr><th>Tab</th><th>موخه</th></tr></thead><tbody><tr><td>Local Node</td><td>خپل node فعالول، public domain تاییدول، shared folders ټاکل او outbound index update کول</td></tr><tr><td>Nodes I Joined</td><td>هغه نور ImgBed nodes manage کول چې join کړي مو دي</td></tr><tr><td>Nodes Joining Me</td><td>د هغو requests manage کول چې نور خلک غواړي ستاسو node ته join شي</td></tr></tbody></table><h2 id="لومړی-setup" tabindex="-1">لومړی Setup <a class="header-anchor" href="#لومړی-setup" aria-label="Permalink to &quot;لومړی Setup&quot;">​</a></h2><ol><li><code>Local Node</code> پرانیزئ.</li><li><code>Enable</code> فعال کړئ.</li><li>د <code>Sync folders</code> لاندې folders وټاکئ چې share کېږي.</li><li><code>Update Outbound Index</code> کلیک کړئ.</li><li>که ImgBed domain change detect کړي، د دوام مخکې تایید کړئ چې اوسنی domain سم دی.</li></ol><p>څو sync folders ټاکلای شئ.</p><p>که sync folder list تش وي، ټول folders share کېږي.</p><h2 id="local-node" tabindex="-1">Local Node <a class="header-anchor" href="#local-node" aria-label="Permalink to &quot;Local Node&quot;">​</a></h2><h3 id="public-domain" tabindex="-1">Public Domain <a class="header-anchor" href="#public-domain" aria-label="Permalink to &quot;Public Domain&quot;">​</a></h3><p>Public domain هغه site URL دی چې نور nodes ستاسو node ته د access لپاره کاروي.</p><p>ImgBed دا په اتومات ډول detect کوي. manually یې لیکلو ته اړتیا نشته. د index د لومړي update پر وخت، ImgBed پوښتنه کوي چې اوسنی access URL production domain دی که نه.</p><p>که وروسته domain بدل کړئ، index update بیا confirmation غواړي.</p><h3 id="sync-folders" tabindex="-1">Sync Folders <a class="header-anchor" href="#sync-folders" aria-label="Permalink to &quot;Sync Folders&quot;">​</a></h3><p>Sync folders ټاکي چې کوم files له federation nodes سره share کېږي.</p><p>د بېلګې په توګه، که یوازې دا وټاکئ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/</span></span>
<span class="line"><span>/2/</span></span></code></pre></div><p>نور nodes یوازې په همدې دوو directories کې files لیدلی شي.</p><h3 id="update-outbound-index" tabindex="-1">Update Outbound Index <a class="header-anchor" href="#update-outbound-index" aria-label="Permalink to &quot;Update Outbound Index&quot;">​</a></h3><p>دا هغه file list update کوي چې نور nodes یې له تاسې sync کولای شي.</p><p>دا په دې وختونو کې وکاروئ:</p><ul><li>federation لومړی ځل فعالوئ.</li><li>هغه files upload کوئ چې share کول یې غواړئ.</li><li>sync folders بدلوئ.</li><li>public domain بدلوئ او تایید ته اړتیا وي.</li></ul><h2 id="nodes-i-joined" tabindex="-1">Nodes I Joined <a class="header-anchor" href="#nodes-i-joined" aria-label="Permalink to &quot;Nodes I Joined&quot;">​</a></h2><p><code>Nodes I Joined</code> هغه ځای دی چې نورو nodes ته subscribe کوئ.</p><p><img src="`+d+'" alt="Nodes I joined" loading="lazy"></p><h3 id="بل-node-ته-د-join-request-لېږل" tabindex="-1">بل Node ته د Join Request لېږل <a class="header-anchor" href="#بل-node-ته-د-join-request-لېږل" aria-label="Permalink to &quot;بل Node ته د Join Request لېږل&quot;">​</a></h3><ol><li>له بل owner څخه invitation link وغواړئ.</li><li>input box ته یې paste کړئ.</li><li><code>Request to Join</code> کلیک کړئ.</li><li>د بل owner approve ته انتظار وکړئ.</li></ol><p>له approval وروسته node status approved کېږي.</p><h3 id="update-inbound-index" tabindex="-1">Update Inbound Index <a class="header-anchor" href="#update-inbound-index" aria-label="Permalink to &quot;Update Inbound Index&quot;">​</a></h3><p><code>Update Inbound Index</code> له هغو nodes څخه file lists sync کوي چې join کړي مو دي.</p><p>دا په دې وختونو کې وکاروئ:</p><ul><li>بل owner ستاسو request تازه approve کړې وي.</li><li>بل owner درته وايي shared content update شوی دی.</li><li>غواړئ ټول joined federation file lists refresh کړئ.</li></ul><p>یوازې د یوه node د update لپاره، په هماغه node card کې <code>Update Index</code> کلیک کړئ.</p><p><img src="'+t+'" alt="Update index" loading="lazy"></p><h3 id="unsubscribe" tabindex="-1">Unsubscribe <a class="header-anchor" href="#unsubscribe" aria-label="Permalink to &quot;Unsubscribe&quot;">​</a></h3><p>که نور نه غواړئ یو node sync کړئ، <code>Unsubscribe</code> کلیک کړئ.</p><p>له unsubscribe وروسته، د هغه node federated index ستاسو له local site څخه لرې کېږي.</p><h2 id="nodes-joining-me" tabindex="-1">Nodes Joining Me <a class="header-anchor" href="#nodes-joining-me" aria-label="Permalink to &quot;Nodes Joining Me&quot;">​</a></h2><p><code>Nodes Joining Me</code> هغه ځای دی چې د نورو خلکو requests handle کوئ.</p><p><img src="'+i+'" alt="Nodes joining me" loading="lazy"></p><h3 id="invitation-link-جوړول" tabindex="-1">Invitation Link جوړول <a class="header-anchor" href="#invitation-link-جوړول" aria-label="Permalink to &quot;Invitation Link جوړول&quot;">​</a></h3><ol><li>ډاډه شئ local node فعال دی.</li><li>لږ تر لږه یو ځل <code>Update Outbound Index</code> کلیک کړئ، څو ImgBed public domain تایید کړي.</li><li><code>Nodes Joining Me</code> پرانیزئ.</li><li><code>Reset Invitation Link</code> کلیک کړئ.</li><li>invitation link copy کړئ او بل owner ته یې ولېږئ.</li></ol><p>که invitation link تش وي، عموما public domain لا confirm شوی نه وي. بېرته <code>Local Node</code> ته لاړ شئ او <code>Update Outbound Index</code> کلیک کړئ.</p><h3 id="join-requests-handle-کول" tabindex="-1">Join Requests Handle کول <a class="header-anchor" href="#join-requests-handle-کول" aria-label="Permalink to &quot;Join Requests Handle کول&quot;">​</a></h3><p>کله چې څوک request submit کړي، د <code>Nodes Joining Me</code> په list کې ښکاري.</p><table tabindex="0"><thead><tr><th>Action</th><th>معنا</th></tr></thead><tbody><tr><td>Approve</td><td>بل node ته اجازه ورکوي چې ستاسو shared file list sync کړي</td></tr><tr><td>Reject</td><td>join request ردوي</td></tr><tr><td>Delete</td><td>بشپړ record لرې کوي</td></tr><tr><td>Check Status</td><td>ګوري چې مقابل لوری لا هم دا relationship ساتي که نه</td></tr></tbody></table><p>له approval وروسته، مقابل لوری باید لا هم <code>Update Inbound Index</code> کلیک کړي، بیا ستاسو shared files هلته ښکاره کېږي.</p><p><img src="'+o+'" alt="Approve invited node" loading="lazy"></p><h2 id="messages" tabindex="-1">Messages <a class="header-anchor" href="#messages" aria-label="Permalink to &quot;Messages&quot;">​</a></h2><p>کله چې relationship approve شي، په node card کې <code>Message</code> کلیک کړئ.</p><p>Messages یوازې د federation relationship په اړه د communication لپاره دي. files، tags، directories یا permissions نه بدلوي.</p><p><img src="'+n+'" alt="Messages" loading="lazy"></p><h2 id="federated-files-لیدل" tabindex="-1">Federated Files لیدل <a class="header-anchor" href="#federated-files-لیدل" aria-label="Permalink to &quot;Federated Files لیدل&quot;">​</a></h2><p>کله چې sync بشپړ شي، بېرته admin file list ته لاړ شئ.</p><p>د پاڼې په سر کې د local files او federated files تر منځ switch وکړئ. په federated files کې synced content browse کولای شئ.</p><p>Federated files عموما د viewing، searching، previewing او links copy کولو لپاره دي. دا local files نه دي، نو له خپل site څخه یې move، delete، retag یا backup نه شئ کولای.</p><p><img src="'+s+'" alt="Federated files in admin" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="ولې-وايي-relationship-record-نشته-او-reapply-وکړئ؟" tabindex="-1">ولې وايي Relationship Record نشته او Reapply وکړئ؟ <a class="header-anchor" href="#ولې-وايي-relationship-record-نشته-او-reapply-وکړئ؟" aria-label="Permalink to &quot;ولې وايي Relationship Record نشته او Reapply وکړئ؟&quot;">​</a></h3><p>دا عموما معنا لري چې مقابل لوري تاسې delete کړي او record یې لرې کړی دی، نو relationship نور نه موندل کېږي. نوی join request submit کړئ.</p><p><img src="'+l+'" alt="Reapply when no relationship record exists" loading="lazy"></p><h3 id="له-join-وروسته-ولې-files-نه-وینم؟" tabindex="-1">له Join وروسته ولې Files نه وینم؟ <a class="header-anchor" href="#له-join-وروسته-ولې-files-نه-وینم؟" aria-label="Permalink to &quot;له Join وروسته ولې Files نه وینم؟&quot;">​</a></h3><p>وګورئ:</p><ol><li>بل owner ستاسو request approve کړې ده.</li><li>بل owner <code>Update Outbound Index</code> کلیک کړی دی.</li><li>تاسې <code>Update Inbound Index</code> کلیک کړی دی.</li><li>د بل owner sync folders هغه directories رانغاړي چې share کول غواړي.</li></ol><h3 id="کله-چې-domain-change-detect-شي-څه-وکړم؟" tabindex="-1">کله چې Domain Change Detect شي څه وکړم؟ <a class="header-anchor" href="#کله-چې-domain-change-detect-شي-څه-وکړم؟" aria-label="Permalink to &quot;کله چې Domain Change Detect شي څه وکړم؟&quot;">​</a></h3><p>که admin panel اوس د production domain له لارې پرانستی وي، confirm او continue کړئ.</p><p>که temporary address کاروئ، cancel کړئ، admin panel د production domain له لارې بیا پرانیزئ، بیا هڅه وکړئ.</p><h3 id="empty-sync-folder-list-څه-معنا-لري؟" tabindex="-1">Empty Sync Folder List څه معنا لري؟ <a class="header-anchor" href="#empty-sync-folder-list-څه-معنا-لري؟" aria-label="Permalink to &quot;Empty Sync Folder List څه معنا لري؟&quot;">​</a></h3><p>تش sync folder list معنا دا ده چې ټول folders share کېږي.</p><p>که یوازې ځینې directories share کوئ، هغه folders manually وټاکئ.</p><h3 id="د-outbound-او-inbound-index-update-توپیر" tabindex="-1">د Outbound او Inbound Index Update توپیر <a class="header-anchor" href="#د-outbound-او-inbound-index-update-توپیر" aria-label="Permalink to &quot;د Outbound او Inbound Index Update توپیر&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Button</th><th>ساده معنا</th></tr></thead><tbody><tr><td>Update Outbound Index</td><td>هغه څه update کوي چې نور یې له ما sync کولای شي</td></tr><tr><td>Update Inbound Index</td><td>هغه څه update کوي چې ما له نورو sync کړي دي</td></tr></tbody></table>',78)])])}const _=r(u,[["render",b]]);export{k as __pageData,_ as default};
